function buildMarkDown() { 
  var md = `# Interview Summary

${global.summary}

## Q&A

${interview.map(qa => `**Q:** ${qa.q}
**A:** ${qa.a}`).join('\n\n')}`;
  return md; 
}

var interview = (context.interview || []).slice();
interview.push({ q: input.question, a: input.answer});
setContext('interview', interview);
var decision = input.decision;
if (decision === 'Completed') {
  setOuput(buildMarkDown());
}

setNodePath(decision);
